create table comment (commented_when timestamp(6), id bigint generated by default as identity, ticket_ticket_id bigint, commenter_user_id uuid, comment_text varchar(255), primary key (id));
create table complaint_ticket (sla_hours integer, assigned_when timestamp(6), cancelled_when timestamp(6), closed_when timestamp(6), created_when timestamp(6), solution_type_id bigint, ticket_element_id bigint, ticket_id bigint generated by default as identity, assigned_to_user_id uuid, cancelled_by_user_id uuid, closed_by_user_id uuid, created_by_user_id uuid, customer_customer_id uuid, description varchar(255), solution_description varchar(255), ticket_status varchar(255) check (ticket_status in ('NEW','ASSIGNED','IN_PROGRESS','RESOLVED','CLOSED','CANCELLED')), ticket_type varchar(255) check (ticket_type in ('COMPLAINT','REQUEST','INCIDENT')), primary key (ticket_id));
create table confirmation_token (expiry_date timestamp(6) not null, id bigint generated by default as identity, user_id uuid not null, token varchar(255) not null unique, primary key (id));
create table customer (customer_id uuid not null, email varchar(255), first_name varchar(255), last_name varchar(255), phone_number varchar(255), primary key (customer_id));
create table solution_type (solution_type_status smallint check (solution_type_status between 0 and 1), id bigint generated by default as identity, name varchar(255), primary key (id));
create table ticket_element (ticket_element_status smallint check (ticket_element_status between 0 and 1), id bigint generated by default as identity, name varchar(255), primary key (id));
create table ticketing_user (account_enabled boolean not null, created_at timestamp(6) not null, user_id uuid not null, username varchar(50) not null unique, email varchar(255) not null unique, first_name varchar(255) not null, last_name varchar(255) not null, password varchar(255) not null, user_role varchar(255) not null check (user_role in ('ADMIN','USER','SUPERVISOR')), primary key (user_id));
alter table if exists comment add constraint FKf5supwgj83p8kfr3akkjxo6y foreign key (commenter_user_id) references ticketing_user;
alter table if exists comment add constraint FKqr2gcy67upd2mbvyxunfr764n foreign key (ticket_ticket_id) references complaint_ticket;
alter table if exists complaint_ticket add constraint FKswesej9coyc3wc4mb7ufrp3vf foreign key (assigned_to_user_id) references ticketing_user;
alter table if exists complaint_ticket add constraint FKgqnse97xf6ooi01xgme654wev foreign key (cancelled_by_user_id) references ticketing_user;
alter table if exists complaint_ticket add constraint FKjhibb5jneosln2b57wa6v3j7q foreign key (closed_by_user_id) references ticketing_user;
alter table if exists complaint_ticket add constraint FKm3nxa7gspc3hi8o6nma6cra1p foreign key (created_by_user_id) references ticketing_user;
alter table if exists complaint_ticket add constraint FKcb7byo7mh613semwdx0bfrbsa foreign key (customer_customer_id) references customer;
alter table if exists complaint_ticket add constraint FKt4wtt58bs4rx7y1ohsjcl230j foreign key (solution_type_id) references solution_type;
alter table if exists complaint_ticket add constraint FKovqb57da15y7viewssbj99jcd foreign key (ticket_element_id) references ticket_element;
